        const map = L.map('map').setView([-6.200000, 106.816666], 13); // Lokasi default: Jakarta

        // Tambahkan layer Map
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: '&copy; <a href="https://www.tiktok.com/@mantanamv?_t=8rZvpk5WhVA&_r=1">Bafandi Navigation</a> contributors'
        }).addTo(map);

        // Tambahkan kontrol geokode
        const geocoder = L.Control.Geocoder.nominatim();

        // Fungsi untuk menghitung rute
        function calculateRoute() {
            const origin = document.getElementById("origin").value;
            const destination = document.getElementById("destination").value;

            if (!origin || !destination) {
                alert("Harap isi lokasi asal dan tujuan!");
                return;
            }

            // Geokode lokasi asal
            geocoder.geocode(origin, function (resultsOrigin) {
                if (resultsOrigin.length === 0) {
                    alert("Lokasi asal tidak ditemukan.");
                    return;
                }

                const start = resultsOrigin[0].center; // Koordinat lokasi asal

                // Geokode lokasi tujuan
                geocoder.geocode(destination, function (resultsDestination) {
                    if (resultsDestination.length === 0) {
                        alert("Lokasi tujuan tidak ditemukan.");
                        return;
                    }

                    const end = resultsDestination[0].center; // Koordinat lokasi tujuan

                    // Membuat rute
                    const routeControl = L.Routing.control({
                        waypoints: [L.latLng(start), L.latLng(end)],
                        routeWhileDragging: true, // Aktifkan drag & drop
                        createMarker: function(i, waypoint, n) {
                            return L.marker(waypoint.latLng, {
                                draggable: true // Marker dapat digeser
                            });
                        },
                        lineOptions: {
                            styles: [{ color: '#007BFF', weight: 5, opacity: 0.8 }] // Gaya rute
                        },
                        addWaypoints: false, // Menghilangkan kotak "Start" dan "End"
                        show: false, // Menyembunyikan kontrol UI tambahan seperti container routing
                        routeDrag: false, // Menonaktifkan fitur untuk menggerakkan rute
                        createAltRoute: false // Menghindari penciptaan alternatif rute
                    }).addTo(map);

                    updateRouteInfo(routeControl, start, end); // Perbarui informasi rute
                });
            });
        }

        // Fungsi untuk memperbarui informasi rute
        function updateRouteInfo(control, start, end) {
            control.on('routesfound', function(e) {
                const route = e.routes[0];
                const distance = (route.summary.totalDistance / 1000).toFixed(2); // Dalam kilometer
                const duration = (route.summary.totalTime / 60).toFixed(0); // Dalam menit

                // Perbarui informasi rute
                document.getElementById("start-info").innerText = `${start.lat.toFixed(5)}, ${start.lng.toFixed(5)}`;
                document.getElementById("end-info").innerText = `${end.lat.toFixed(5)}, ${end.lng.toFixed(5)}`;
                document.getElementById("distance-info").innerText = `${distance} km`;
                document.getElementById("duration-info").innerText = `${duration} menit`;

                // Tambahkan langkah-langkah perjalanan
                const stepsContainer = document.getElementById("route-steps");
                stepsContainer.innerHTML = ""; // Kosongkan langkah sebelumnya

                route.instructions.forEach(step => {
                    const li = document.createElement("li");
                    li.textContent = step.text;
                    stepsContainer.appendChild(li);
                });
            });
        }`,
   language: 'javascript',
   footerText: 'Pretty simple, right?'
})

*─「 EVAL ERROR 」─*

```
Unexpected identifier '$'
```

Error itu terjadi karena kamu menggunakan **backticks** (`` ` ``) di dalam **backticks**.

Di JavaScript, kalau kamu menulis `${...}` di dalam template literal (backticks), JS akan menganggap itu adalah variabel yang harus diisi nilainya saat itu juga. Karena variabel `start`, `end`, `distance`, dan `duration` tidak ada di sistem bot (mereka cuma teks kode), maka terjadilah error `Unexpected identifier '$'`.

**Solusinya:** Kamu harus memberikan *escape character* berupa backslash (`\`) sebelum tanda `$` agar JS menganggapnya sebagai teks biasa, bukan variabel.

